html = "<!doctype html>\n<html>\n<head>\n<meta charset=\"utf-8\">\n<style>\n:root{\n  --bg:#070910;\n  --grid-line:#4a3510;\n  --cell-bg:#172033;\n  --cell-bg-2:#1b2740;\n  --cell-marked:#138a52;\n  --cell-free:#532e86;\n  --gold:#ffd166;\n  --gold2:#ffb703;\n  --red:#ef476f;\n  --blue:#4cc9f0;\n  --green:#06d6a0;\n  --purple:#b517ff;\n  --text:#f8fafc;\n  --muted:#a8b3c7;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  width:100%;\n  height:100%;\n  background:var(--bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  overflow:hidden;\n}\n.app{\n  width:535px;\n  height:620px;\n  max-width:100vw;\n  max-height:100vh;\n  margin:0 auto;\n  background:var(--bg);\n  display:flex;\n  flex-direction:column;\n}\n.header{\n  background:var(--bg);\n  display:flex;\n  align-items:flex-start;\n  justify-content:center;\n  padding-top:7px;\n  flex:0 0 auto;\n}\n.dice{\n  font-family:\"Segoe UI Symbol\",\"Segoe UI\",Arial,sans-serif;\n  font-size:24px;\n  line-height:28px;\n  color:var(--gold);\n  background:var(--bg);\n  width:40px;\n  text-align:center;\n  margin:0 8px;\n}\n.title-wrap{\n  background:var(--bg);\n  text-align:center;\n}\n.title{\n  color:var(--gold);\n  background:var(--bg);\n  font-size:18px;\n  line-height:22px;\n  font-weight:700;\n  text-align:center;\n}\n.subtitle{\n  color:var(--muted);\n  background:var(--bg);\n  font-size:11px;\n  line-height:14px;\n  font-weight:700;\n  text-align:center;\n}\n.controls{\n  background:var(--bg);\n  display:flex;\n  justify-content:center;\n  gap:4px;\n  padding-top:4px;\n  padding-bottom:4px;\n  flex:0 0 auto;\n}\n.btn{\n  background:#251a08;\n  color:var(--gold);\n  border:0;\n  padding:4px 8px;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:8px;\n  font-weight:700;\n  cursor:pointer;\n  min-height:24px;\n  min-width:0;\n}\n.btn:hover{\n  background:#4a320b;\n  color:#fff4c7;\n}\n.btn:active{filter:brightness(.85)}\n.neon{\n  height:2px;\n  background:var(--gold);\n  margin:0 36px 4px 36px;\n  flex:0 0 auto;\n}\n.outer{\n  background:var(--gold2);\n  margin:6px 8px;\n  padding:0;\n  flex:1 1 auto;\n  min-height:0;\n  display:flex;\n}\n.inner{\n  background:#2b210e;\n  margin:2px;\n  flex:1 1 auto;\n  min-height:0;\n  display:flex;\n}\n.grid{\n  background:var(--grid-line);\n  margin:2px;\n  flex:1 1 auto;\n  min-height:0;\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  grid-template-rows:repeat(5,1fr);\n}\n.cell{\n  margin:1px;\n  border:0;\n  background:var(--cell-bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:8px;\n  line-height:1.12;\n  font-weight:700;\n  text-align:center;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  padding:1px 2px;\n  cursor:pointer;\n  user-select:none;\n  white-space:pre-line;\n  overflow:hidden;\n}\n.cell.alt{background:var(--cell-bg-2)}\n.cell:hover:not(.free){\n  background:#263554;\n  color:#ffffff;\n}\n.cell.free{\n  background:var(--cell-free);\n  color:var(--gold);\n  cursor:default;\n  font-size:11px;\n  font-weight:700;\n  font-style:italic;\n}\n.cell.free:hover{\n  background:var(--cell-free);\n  color:var(--gold);\n}\n.cell.marked{\n  background:var(--cell-marked)!important;\n  color:#ecfff4;\n}\n.cell.pulse0{\n  background:#2ee88e!important;\n  color:#ecfff4;\n}\n.cell.pulse1{\n  background:#20b875!important;\n  color:#ecfff4;\n}\n.status{\n  background:var(--bg);\n  color:var(--muted);\n  font-size:8px;\n  line-height:13px;\n  text-align:center;\n  padding-bottom:5px;\n  flex:0 0 auto;\n}\n.rules-layer{\n  position:fixed;\n  inset:0;\n  display:none;\n  background:#000000;\n  z-index:40;\n}\n.rules-layer.show{display:block}\n.rules-card{\n  position:absolute;\n  left:50%;\n  top:50%;\n  transform:translate(-50%,-50%);\n  width:78%;\n  height:45%;\n  background:#141a24;\n  color:var(--text);\n  text-align:center;\n  padding-top:20px;\n}\n.rules-title{\n  color:var(--gold);\n  font-size:26px;\n  line-height:32px;\n  font-weight:700;\n  margin-bottom:8px;\n}\n.rules-text{\n  display:inline-block;\n  text-align:left;\n  color:var(--text);\n  font-size:12px;\n  line-height:18px;\n  font-weight:700;\n  margin-top:6px;\n}\n.rules-hint{\n  color:var(--muted);\n  font-size:9px;\n  line-height:14px;\n  margin-top:10px;\n}\n.bingo-layer{\n  position:fixed;\n  inset:0;\n  display:none;\n  background:#000000;\n  z-index:50;\n}\n.bingo-layer.show{display:block}\n.bingo-text{\n  position:absolute;\n  left:50%;\n  top:43%;\n  transform:translate(-50%,-50%);\n  color:var(--gold);\n  font-size:50px;\n  line-height:60px;\n  font-weight:700;\n  white-space:nowrap;\n}\n.bingo-sub{\n  position:absolute;\n  left:50%;\n  top:56%;\n  transform:translate(-50%,-50%);\n  color:var(--text);\n  font-size:15px;\n  line-height:22px;\n  font-weight:700;\n  white-space:nowrap;\n}\n.bingo-hint{\n  position:absolute;\n  left:50%;\n  top:65%;\n  transform:translate(-50%,-50%);\n  color:var(--muted);\n  font-size:9px;\n  line-height:14px;\n  white-space:nowrap;\n}\n.star{\n  position:fixed;\n  background:#000000;\n  pointer-events:none;\n  z-index:55;\n  font-weight:700;\n}\n@media(max-width:535px){\n  .app{\n    width:100vw;\n  }\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n  <div class=\"header\">\n    <div class=\"dice\" id=\"leftDice\">\u2684</div>\n    <div class=\"title-wrap\">\n      <div class=\"title\" id=\"title\">\u2726 Wings of Glory \u2726</div>\n      <div class=\"subtitle\">LOW RANK BINGO</div>\n    </div>\n    <div class=\"dice\" id=\"rightDice\">\u2682</div>\n  </div>\n\n  <div class=\"controls\">\n    <button class=\"btn\" onclick=\"rollClicked()\">Roll \ud83c\udfb2</button>\n    <button class=\"btn\" onclick=\"resetMarks()\">Reset</button>\n    <button class=\"btn\" onclick=\"showRules()\">Bingo?</button>\n    <button class=\"btn\" onclick=\"toggleFullscreen()\">Full</button>\n  </div>\n\n  <div class=\"neon\" id=\"neonBar\"></div>\n\n  <div class=\"outer\">\n    <div class=\"inner\">\n      <div class=\"grid\" id=\"grid\"></div>\n    </div>\n  </div>\n\n  <div class=\"status\" id=\"status\">Roll, mark squares, chase bingo.</div>\n</div>\n\n<div class=\"rules-layer\" id=\"rulesLayer\" onclick=\"hideRules()\">\n  <div class=\"rules-card\" id=\"rulesCard\">\n    <div class=\"rules-title\">RULES</div>\n    <div class=\"rules-text\">\u2022 Click a square when it happens<br>\u2022 FREE SPACE is already marked<br>\u2022 5 in a row = BINGO<br>\u2022 Rows, columns, diagonals count<br>\u2022 Roll makes a new random board</div>\n    <div class=\"rules-hint\">click anywhere or press Esc to close</div>\n  </div>\n</div>\n\n<div class=\"bingo-layer\" id=\"bingoLayer\" onclick=\"hideBingoOverlay()\">\n  <div class=\"bingo-text\" id=\"bingoText\">BINGO!</div>\n  <div class=\"bingo-sub\">JACKPOT HIT</div>\n  <div class=\"bingo-hint\">click anywhere or press Esc to close</div>\n</div>\n\n<script>\nconst BINGO_ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\n\nconst COLORS = {\n  bg:\"#070910\",\n  gridLine:\"#4a3510\",\n  cellBg:\"#172033\",\n  cellBg2:\"#1b2740\",\n  cellMarked:\"#138a52\",\n  cellFree:\"#532e86\",\n  gold:\"#ffd166\",\n  gold2:\"#ffb703\",\n  red:\"#ef476f\",\n  blue:\"#4cc9f0\",\n  green:\"#06d6a0\",\n  purple:\"#b517ff\",\n  text:\"#f8fafc\",\n  muted:\"#a8b3c7\"\n};\n\nlet buttons = [];\nlet marked = new Set([12]);\nlet diceFaces = [\"\u2680\",\"\u2681\",\"\u2682\",\"\u2683\",\"\u2684\",\"\u2685\"];\nlet animating = false;\nlet idleTick = 0;\nlet boardHasBingo = false;\nlet currentBoard = [];\n\nfunction randomChoice(arr){\n  return arr[Math.floor(Math.random()*arr.length)];\n}\n\nfunction shuffle(arr){\n  const a = arr.slice();\n  for(let i=a.length-1;i>0;i--){\n    const j = Math.floor(Math.random()*(i+1));\n    const t = a[i]; a[i]=a[j]; a[j]=t;\n  }\n  return a;\n}\n\nfunction generateItems(){\n  const items = shuffle(BINGO_ITEMS);\n  const board = [];\n  let itemI = 0;\n  for(let i=0;i<25;i++){\n    if(i===12) board.push(\"FREE SPACE\");\n    else board.push(items[itemI++]);\n  }\n  return board;\n}\n\nfunction buildGrid(){\n  const grid = document.getElementById(\"grid\");\n  grid.innerHTML = \"\";\n  buttons = [];\n  for(let row=0;row<5;row++){\n    const rowButtons = [];\n    for(let col=0;col<5;col++){\n      const index = row*5+col;\n      const btn = document.createElement(\"div\");\n      btn.className = \"cell\";\n      btn.dataset.index = index;\n      btn.onclick = function(){ toggleCell(index); };\n      grid.appendChild(btn);\n      rowButtons.push(btn);\n    }\n    buttons.push(rowButtons);\n  }\n}\n\nfunction applyBoard(board){\n  currentBoard = board.slice();\n  marked = new Set([12]);\n  boardHasBingo = false;\n\n  for(let row=0;row<5;row++){\n    for(let col=0;col<5;col++){\n      const index = row*5+col;\n      const btn = buttons[row][col];\n      const item = board[index];\n      btn.originalText = item;\n      btn.style.background = \"\";\n      btn.style.color = \"\";\n      btn.className = \"cell\";\n\n      if(index===12){\n        btn.className = \"cell free marked\";\n        btn.textContent = \"FREE\\nSPACE\";\n      }else{\n        if((row+col)%2===1) btn.classList.add(\"alt\");\n        btn.textContent = item;\n      }\n    }\n  }\n  setTimeout(updateTextFit,20);\n}\n\nfunction wrapText(text,maxChars){\n  const words = text.split(/\\s+/);\n  let lines = [];\n  let line = \"\";\n  for(const word of words){\n    if(!line) line = word;\n    else if(line.length + 1 + word.length <= maxChars) line += \" \" + word;\n    else{\n      lines.push(line);\n      line = word;\n    }\n  }\n  if(line) lines.push(line);\n  return lines.join(\"\\n\");\n}\n\nfunction updateTextFit(){\n  const grid = document.getElementById(\"grid\");\n  const cellW = Math.max(50, Math.floor(grid.clientWidth/5) - 8);\n  const cellH = Math.max(45, Math.floor(grid.clientHeight/5) - 8);\n\n  let fontSize = 9;\n  let maxChars = 16;\n\n  if(cellW < 80 || cellH < 70){\n    fontSize = 6; maxChars = 10;\n  }else if(cellW < 100 || cellH < 85){\n    fontSize = 7; maxChars = 12;\n  }else if(cellW < 120 || cellH < 100){\n    fontSize = 8; maxChars = 14;\n  }\n\n  for(let row=0;row<5;row++){\n    for(let col=0;col<5;col++){\n      const btn = buttons[row][col];\n      const original = btn.originalText || btn.textContent;\n      if(row===2 && col===2){\n        btn.textContent = \"FREE\\nSPACE\";\n        btn.style.fontSize = Math.max(10,fontSize+3) + \"px\";\n        btn.style.fontWeight = \"700\";\n        btn.style.fontStyle = \"italic\";\n      }else{\n        btn.textContent = wrapText(original,maxChars);\n        btn.style.fontSize = fontSize + \"px\";\n        btn.style.fontWeight = \"700\";\n        btn.style.fontStyle = \"normal\";\n      }\n    }\n  }\n}\n\nfunction rollClicked(){\n  rollBoard(true);\n}\n\nfunction rollBoard(animated){\n  if(animating) return;\n  const finalBoard = generateItems();\n\n  if(!animated){\n    applyBoard(finalBoard);\n    return;\n  }\n\n  animating = true;\n  document.getElementById(\"status\").textContent = \"Rolling...\";\n  animateDice(0);\n  const steps = 14;\n\n  function spin(step){\n    const temp = generateItems();\n    for(let i=0;i<25;i++){\n      const r = Math.floor(i/5);\n      const c = i%5;\n      const btn = buttons[r][c];\n\n      btn.className = \"cell\";\n      btn.style.background = \"\";\n      btn.style.color = \"\";\n\n      if(i===12){\n        btn.originalText = \"FREE SPACE\";\n        btn.className = \"cell free marked\";\n        btn.textContent = \"FREE\\nSPACE\";\n      }else{\n        btn.originalText = temp[i];\n        if((r+c)%2===1) btn.classList.add(\"alt\");\n        btn.style.background = randomChoice([COLORS.cellBg, COLORS.cellBg2, \"#2a1f3d\", \"#263554\"]);\n        btn.style.color = randomChoice([COLORS.text, COLORS.gold, COLORS.blue]);\n      }\n    }\n\n    updateTextFit();\n\n    if(step < steps){\n      setTimeout(function(){ spin(step+1); },30 + step*6);\n    }else{\n      applyBoard(finalBoard);\n      flashTitle(0);\n      document.getElementById(\"status\").textContent = \"Rolled. Click squares to mark.\";\n      animating = false;\n    }\n  }\n\n  spin(0);\n}\n\nfunction animateDice(step){\n  const left = document.getElementById(\"leftDice\");\n  const right = document.getElementById(\"rightDice\");\n  left.textContent = randomChoice(diceFaces);\n  right.textContent = randomChoice(diceFaces);\n  left.style.color = randomChoice([COLORS.gold,COLORS.blue,COLORS.red,COLORS.green]);\n  right.style.color = randomChoice([COLORS.gold,COLORS.blue,COLORS.red,COLORS.green]);\n\n  if(step < 18){\n    setTimeout(function(){ animateDice(step+1); },65);\n  }else{\n    left.textContent = randomChoice(diceFaces);\n    right.textContent = randomChoice(diceFaces);\n    left.style.color = COLORS.gold;\n    right.style.color = COLORS.gold;\n  }\n}\n\nfunction idleAnimation(){\n  const rulesOpen = document.getElementById(\"rulesLayer\").classList.contains(\"show\");\n  const bingoOpen = document.getElementById(\"bingoLayer\").classList.contains(\"show\");\n  if(!animating && !bingoOpen && !rulesOpen){\n    const colors = [COLORS.gold,COLORS.gold2,COLORS.blue,COLORS.green,COLORS.red,COLORS.purple];\n    const color = colors[idleTick % colors.length];\n    document.getElementById(\"neonBar\").style.background = color;\n    document.getElementById(\"leftDice\").style.color = idleTick%2===0 ? color : COLORS.gold;\n    document.getElementById(\"rightDice\").style.color = idleTick%2===1 ? color : COLORS.gold;\n    if(idleTick % 6 === 0){\n      document.getElementById(\"leftDice\").textContent = randomChoice(diceFaces);\n      document.getElementById(\"rightDice\").textContent = randomChoice(diceFaces);\n    }\n    idleTick++;\n  }\n  setTimeout(idleAnimation,650);\n}\n\nfunction flashTitle(n){\n  const title = document.getElementById(\"title\");\n  if(n>=8){\n    title.style.color = COLORS.gold;\n    return;\n  }\n  title.style.color = n%2===0 ? COLORS.blue : COLORS.gold;\n  setTimeout(function(){ flashTitle(n+1); },100);\n}\n\nfunction resetMarks(){\n  marked = new Set([12]);\n  boardHasBingo = false;\n\n  for(let row=0;row<5;row++){\n    for(let col=0;col<5;col++){\n      const index = row*5+col;\n      const btn = buttons[row][col];\n      btn.style.background = \"\";\n      btn.style.color = \"\";\n      btn.className = \"cell\";\n\n      if(index===12){\n        btn.className = \"cell free marked\";\n      }else{\n        if((row+col)%2===1) btn.classList.add(\"alt\");\n      }\n    }\n  }\n  document.getElementById(\"status\").textContent = \"Marks reset.\";\n}\n\nfunction toggleCell(index){\n  if(index===12 || animating) return;\n\n  const row = Math.floor(index/5);\n  const col = index%5;\n  const btn = buttons[row][col];\n\n  if(marked.has(index)){\n    marked.delete(index);\n    btn.style.background = \"\";\n    btn.style.color = \"\";\n    btn.className = \"cell\";\n    if((row+col)%2===1) btn.classList.add(\"alt\");\n    boardHasBingo = false;\n  }else{\n    marked.add(index);\n    btn.style.color = \"#ecfff4\";\n    pulseMark(btn,0);\n  }\n\n  if(hasBingo() && !boardHasBingo){\n    boardHasBingo = true;\n    showBingoOverlay();\n  }\n}\n\nfunction pulseMark(btn,step){\n  const colors = [\"#2ee88e\",\"#20b875\",COLORS.cellMarked];\n  if(step >= colors.length) return;\n  btn.classList.add(\"marked\");\n  btn.style.background = colors[step];\n  btn.style.color = \"#ecfff4\";\n  setTimeout(function(){ pulseMark(btn,step+1); },70);\n}\n\nfunction hasBingo(){\n  const lines = [];\n  for(let row=0;row<5;row++){\n    lines.push([row*5,row*5+1,row*5+2,row*5+3,row*5+4]);\n  }\n  for(let col=0;col<5;col++){\n    lines.push([col,5+col,10+col,15+col,20+col]);\n  }\n  lines.push([0,6,12,18,24]);\n  lines.push([4,8,12,16,20]);\n\n  return lines.some(function(line){\n    return line.every(function(i){ return marked.has(i); });\n  });\n}\n\nfunction showRules(){\n  hideRules();\n  const layer = document.getElementById(\"rulesLayer\");\n  layer.classList.add(\"show\");\n  rulesPulse(0);\n}\n\nfunction rulesPulse(step){\n  const layer = document.getElementById(\"rulesLayer\");\n  if(!layer.classList.contains(\"show\")) return;\n  const card = document.getElementById(\"rulesCard\");\n  const colors = [\"#141a24\",\"#192234\",\"#141a24\"];\n  card.style.background = colors[step % colors.length];\n  if(step < 12){\n    setTimeout(function(){ rulesPulse(step+1); },120);\n  }\n}\n\nfunction hideRules(){\n  document.getElementById(\"rulesLayer\").classList.remove(\"show\");\n}\n\nfunction showBingoOverlay(){\n  hideBingoOverlay();\n  document.getElementById(\"bingoLayer\").classList.add(\"show\");\n  bingoAnimation(0);\n}\n\nfunction bingoAnimation(step){\n  const layer = document.getElementById(\"bingoLayer\");\n  if(!layer.classList.contains(\"show\")) return;\n\n  const colors = [COLORS.gold,COLORS.blue,COLORS.red,COLORS.green,\"#ffffff\",COLORS.purple];\n  const sizes = [48,54,60,56,52,58];\n  const bingoText = document.getElementById(\"bingoText\");\n  bingoText.style.color = randomChoice(colors);\n  bingoText.style.fontSize = sizes[step % sizes.length] + \"px\";\n\n  if(step < 30){\n    for(let s=0;s<6;s++){\n      const star = document.createElement(\"div\");\n      star.className = \"star\";\n      star.textContent = randomChoice([\"\u2726\",\"\u2727\",\"\u2605\",\"\u2666\",\"\u25cf\",\"\u2660\",\"\u2665\"]);\n      star.style.fontSize = (10 + Math.floor(Math.random()*13)) + \"px\";\n      star.style.color = randomChoice(colors);\n      star.style.left = (Math.random()*100) + \"vw\";\n      star.style.top = (Math.random()*100) + \"vh\";\n      document.body.appendChild(star);\n      setTimeout(function(){ star.remove(); },550);\n    }\n\n    setTimeout(function(){ bingoAnimation(step+1); },85);\n  }else{\n    bingoText.style.color = COLORS.gold;\n    bingoText.style.fontSize = \"56px\";\n  }\n}\n\nfunction hideBingoOverlay(){\n  document.getElementById(\"bingoLayer\").classList.remove(\"show\");\n}\n\nfunction toggleFullscreen(){\n  try{\n    if(document.fullscreenElement){\n      document.exitFullscreen();\n    }else{\n      document.documentElement.requestFullscreen();\n    }\n  }catch(e){}\n}\n\ndocument.addEventListener(\"keydown\",function(e){\n  if(e.key===\"Escape\"){\n    if(document.getElementById(\"bingoLayer\").classList.contains(\"show\")){\n      hideBingoOverlay();\n    }else if(document.getElementById(\"rulesLayer\").classList.contains(\"show\")){\n      hideRules();\n    }else if(document.fullscreenElement){\n      document.exitFullscreen();\n    }\n  }\n});\n\nwindow.addEventListener(\"resize\",function(){\n  setTimeout(updateTextFit,30);\n});\n\nbuildGrid();\nrollBoard(false);\nidleAnimation();\n</script>\n</body>\n</html>\n"

components.html(html, height=620, scrolling=False)
